      "armsInterventionsModule": {
        "armGroups": [
          {
            "label": "real TCMS treatment",
            "type": "ACTIVE_COMPARATOR",
            "description": "Subjects with DN located in their bilateral feet that have been previously identified and have a graded average baseline score of at least 5 in each foot will receive either TCMS treatment or Sham treatment on clinic day-1 according to the contents of a sealed opaque envelope corresponding to the subject's number in the series and opened immediately before treatment on day 1. (Our statistician will have generated these envelopes and their contents in advance.) Subjects and staff evaluating the subject's response will remain blinded to treatment assignment; only the staff member setting the treatment mode will know whether it is active or sham.",
            "interventionNames": [
              "Device: Transcutaneous Magnetic Stimulation (TCMS)"
            ]
          },
          {
            "label": "Sham TCMS treatment",
            "type": "SHAM_COMPARATOR",
            "description": "Patients in the sham treatment group, will use the same device. The device will be switched into sham mode by the clinician by pressing a small, non-descript button on the backside of the pulse generator. The treatment device in sham mode will produce a clicking sound once every 6 seconds like the TCMS treatment mode, but no magnetic pulses will be output.",
            "interventionNames": [
              "Device: Transcutaneous Magnetic Stimulation (TCMS)"
            ]
          }
        ],
        "interventions": [
          {
            "type": "DEVICE",
            "name": "Transcutaneous Magnetic Stimulation (TCMS)",
            "description": "The study will evaluate whether an experimental medical device that emits a series of brief, intense magnetic pulse called TCMS will relieve foot pain from Diabetic Neuropathy (DN) when compared to the same device giving a sham treatment without magnetic pulses. Participants will be blindly randomized into either the TCMS treatment group or the sham treatment group according to the number 1-20 that they draw. This is necessary to further investigate this TCMS treatment and to determine how to obtain statistically significant data as to whether this therapy reduces the foot pain caused by diabetic neuropathy.",
            "armGroupLabels": [
              "Sham TCMS treatment",
              "real TCMS treatment"
            ]
          }
        ]
      },
      "outcomesModule": {
        "primaryOutcomes": [
          {
            "measure": "Overall Pain reduction",
            "description": "The primary endpoint will be defined as achieving at least reduction in average pain score from 0-10 (0 being no pain and 10 being the worst pain imaginable) )versus the sham control using pre-study average baseline for each subject as a covariate by a repeated measures analysis of pain scores through 28 days.",
            "timeFrame": "28 day +/- 2 days"
          }
        ],
        "secondaryOutcomes": [
          {
            "measure": "Pain reduction with in the first week",
            "description": "Secondary endpoints will include a responder analysis in which the percentage of subjects between the sham and test groups that achieve the minimum clinically important pain reduction of 2 or more points from the scale described above within the first week of treatment.",
            "timeFrame": "1 week"
          },
          {
            "measure": "Improved Activities of daily living",
            "description": "Secondary endpoints will also include improved quality of life (ie, 1-Did the level of your pain interfere with your daily activities at home or work? 2-Did the level of your pain interfere with your social or recreational activities? 3-Did the level of your pain interfere with your sleep?) the responses as guided by the PROMIS questions ( answered as one of 5 choices Not at All A little bit Somewhat Quite a bit Very Much) included in the pre and post questionnaires and the home assessment diary booklet.",
            "timeFrame": "28 days +/- 2 days"
          }
        ]
      },
      "eligibilityModule": {
        "eligibilityCriteria": "Inclusion Criteria:\n\n1. Age ≥ 18 years of age.\n2. Pain duration of more than one month.\n3. Pain occurs daily.\n4. Chronic DN associated bilateral foot pain and is not explained by a central anatomic nerve compression and can clearly be correlated with that patient's history of diabetes.\n5. Average Pain intensity ≥ 5 in each foot for at least 3 days at the time of enrollment.\n\nExclusion Criteria:\n\n1. Life expectancy ≤ 6 months.\n2. Oral pain medication doses or active ingredient has changed significantly\\* in the prior 2 weeks.\n3. Inability to walk at least 10 steps (with or without a cane/walker) before and after having to sit in a chair.\n4. Another pain condition that might confound results (e.g., neuropathy from cancer chemotherapy, plantar fasciitis or arthritis of ankle and foot)\n5. Inability to undergo study assessments or complete questionnaires independently.\n6. Active psychological co-morbidities (i.e., uncontrolled schizophrenia).\n7. Currently using an opioid medication for the treatment of foot pain\\*\\*.\n8. Pregnancy\n9. Inability to have MRI\n10. Metal hardware and/or fragments in feet and ankles\n11. Implanted pacemaker or a defibrillator, unless the device is considered MRI safe\n\n    * A significant change for this study is defined as a 20% increase or decrease in dosing of the patient's medication dose and/or or a change in the medication class (adding or removing other types of medicines used to treat pain).\n\n      * This exclusion is restricted to opioids, benzodiazepines and psychotropic.",
