    "resultsSection": {
      "participantFlowModule": {
        "preAssignmentDetails": "Adult participants with advanced melanoma, who have not received prior systemic therapy were enrolled. 674 participants were randomly assigned in a 1:1 ratio to either combination therapy, Pembrolizumab+Lenvatinib, or Pembrolizumab+Placebo, to assess the safety and efficacy of combination therapy, Pembrolizumab+Lenvatinib.",
        "groups": [
          {
            "id": "FG000",
            "title": "Pembrolizumab+Lenvatinib",
            "description": "Participants received pembrolizumab 200 mg via intravenous (IV) infusion on Day 1 of each 3-week cycle for up to 35 administrations (up to approximately 2 years) PLUS lenvatinib 20 mg via oral capsule daily for up to at least 2 years."
          },
          {
            "id": "FG001",
            "title": "Pembrolizumab+Placebo",
            "description": "Participants received pembrolizumab 200 mg via IV infusion on Day 1 of each 3-week cycle for up to 35 administrations (up to approximately 2 years) PLUS placebo for lenvatinib via oral capsule daily for up to at least 2 years."
          }
        ],
